import{_ as t,c as o,a2 as a,o as n}from"./chunks/framework.DPuwY6B9.js";const h=JSON.parse('{"title":"Web Development Stacks","description":"Web technology sets that include all the essential parts of a modern app - the frontend framework, the backend solution and the database.","frontmatter":{"title":"Web Development Stacks","description":"Web technology sets that include all the essential parts of a modern app - the frontend framework, the backend solution and the database."},"headers":[],"relativePath":"Concepts/Web/Web_Development_Stacks.md","filePath":"Concepts/Web/Web_Development_Stacks.md","lastUpdated":1666469073000}'),s={name:"Concepts/Web/Web_Development_Stacks.md"};function l(r,e,i,c,p,d){return n(),o("div",null,e[0]||(e[0]=[a('<h1 id="web-development-stacks" tabindex="-1">Web Development Stacks <a class="header-anchor" href="#web-development-stacks" aria-label="Permalink to &quot;Web Development Stacks&quot;">​</a></h1><p>A full stack web developer is a person who can develop both <strong>client</strong> and <strong>server</strong> software. So the developer has to learn tools used for both client side development and server side development.</p><p>Web Development Stacks are combination of tools that are used while building a web or mobile application. There are many combination of these tools forming different stacks.</p><p>The choice of tools depends on lot of variables like:</p><ul><li>Technology of the tool.</li><li>Programming Language of the tool.</li><li>Proficiency of the Developer in the Programming Language or the tool itself.</li></ul><p>Some of the more popular Web Stacks are:</p><ol><li><strong>LAMP Stack</strong> <em>(Linux, Apache, MySQL, PHP)</em>: The Old-school Stack</li><li><strong>MEAN</strong> <em>(MongoDB, ExpressJS, Angular, NodeJS)</em>: The Jock Stack</li><li><strong>MERN</strong> <em>(MongoDB, ExpressJS, ReactJS, NodeJS)</em></li></ol>',7)]))}const b=t(s,[["render",l]]);export{h as __pageData,b as default};
